class SafeModelLoader:
    def __init__(self, trusted_hashes=None):
        self.trusted_hashes = trusted_hashes or {}
        self.model_cache = {}
        
    def verify_model_integrity(self, model_path, expected_hash):
        """Verify model integrity using SHA-256 hash"""
        if not os.path.exists(model_path):
            return False
            
        with open(model_path, 'rb') as f:
            file_hash = hashlib.sha256(f.read()).hexdigest()
            
        return file_hash == expected_hash
    
    def download_model(self, url, model_path, expected_hash=None):
        """Download model from URL with optional integrity check"""
        if model_path in self.model_cache:
            return self.model_cache[model_path]
            
        response = requests.get(url, stream=True)
        response.raise_for_status()
        
        with open(model_path, 'wb') as f:
            for chunk in response.iter_content(chunk_size=8192):
                if chunk:
                    f.write(chunk)
        
        if expected_hash and not self.verify_model_integrity(model_path, expected_hash):
            raise ValueError("Model integrity check failed")
            
        self.model_cache[model_path] = model_path
        return model_path

class CustomDataset(Dataset):
    def __init__(self, data, labels, transform=None):
        self.data = data
        self.labels = labels
        self.transform = transform
        
    def __len__(self):
        return len(self.data)
        
    def __getitem__(self, idx):
        sample = self.data[idx]
        label = self.labels[idx]
        
        if self.transform:
            sample = self.transform(sample)
            
        return sample, label

